# Auth helpers (AAD token + Purview client)
def azuread_auth(tenant_id: str, client_id: str, client_secret: str, resource_url: str = 'https://purview.azure.net') -> str:
    token_endpoint = f'https://login.microsoftonline.com/{tenant_id}/oauth2/v2.0/token'
    data = {
        'grant_type': 'client_credentials',
        'client_id': client_id,
        'client_secret': client_secret,
        'scope': f'{resource_url}/.default'
    }
    resp = requests.post(token_endpoint, data=data, timeout=30)
    resp.raise_for_status()
    return resp.json()['access_token']

def purview_auth(tenant_id: str, client_id: str, client_secret: str, account_name: str, resource_url: str = 'https://purview.azure.net') -> PurviewClient:
    oauth = ServicePrincipalAuthentication(tenant_id=tenant_id, client_id=client_id, client_secret=client_secret, resource_url=resource_url)
    return PurviewClient(account_name=account_name, authentication=oauth)

def purview_rest(method: str, path: str, token: str, *, params=None, json_body=None, timeout: int = 60) -> requests.Response:
    url = f'https://{PURVIEW_ACCOUNT_NAME}.purview.azure.com{path}'
    headers = {'Authorization': f'Bearer {token}', 'Content-Type': 'application/json'}
    return requests.request(method, url, headers=headers, params=params, json=json_body, timeout=timeout)

# ADLS helpers: recursive listing using mssparkutils
def deep_ls(path: str, max_depth: int = 20, _depth: int = 0):
    try:
        entries = mssparkutils.fs.ls(path)
    except Exception as e:
        print(f'ls failed at {path}: {e}')
        return
    for it in entries:
        name = getattr(it, 'name', None) or os.path.basename(getattr(it, 'path', ''))
        p = getattr(it, 'path', None) or name
        is_dir = getattr(it, 'isDir', None)
        if is_dir is None:
            is_dir = not bool(getattr(it, 'isFile', False))
        yield { 'path': p, 'name': name, 'isDir': bool(is_dir) }
        if bool(is_dir) and _depth < max_depth:
            yield from deep_ls(p, max_depth, _depth + 1)

def convertfiles2df(files: list) -> pd.DataFrame:
    df = pd.DataFrame(files)
    if not df.empty:
        df['basename'] = df['path'].apply(lambda s: s.split('/')[-1])
    return df

# Purview query helpers
def search_atlas_basic(token: str, *, query: str, type_name: str = None, classification: str = None, limit: int = 100, offset: int = 0) -> dict:
    params = { 'query': query, 'limit': limit, 'offset': offset }
    if type_name: params['typeName'] = type_name
    if classification: params['classification'] = classification
    resp = purview_rest('GET', '/catalog/api/atlas/v2/search/basic', token, params=params)
    resp.raise_for_status()
    return resp.json()

def get_all_adls_assets(top_path: str, token: str, *, max_pages: int = 100, page_size: int = 100) -> list:
    results = []
    offset = 0
    for _ in range(max_pages):
        data = search_atlas_basic(token, query=top_path, type_name=None, limit=page_size, offset=offset)
        items = data.get('entities') or []
        if not items:
            break
        results.extend(items)
        if len(items) < page_size:
            break
        offset += page_size
    return results

def abfss_to_purview_subpath(abfss_path: str, storage_account: str, container: str) -> str:
    prefix = f'abfss://{container}@{storage_account}.dfs.core.windows.net/'
    rel = abfss_path.split(prefix, 1)[-1] if prefix in abfss_path else abfss_path
    return f'/azure_datalake_gen2_filesystem#{container}/{rel}'.rstrip('/')

def get_adls_asset_schema(abfss_path: str, token: str, *, storage_account: str, container: str, classification_filter: list = None) -> list:
    sub = abfss_to_purview_subpath(abfss_path, storage_account, container)
    cols = []
    offset = 0
    page = 0
    while page < 50:
        data = search_atlas_basic(token, query=sub, type_name='column', limit=200, offset=offset)
        entities = data.get('entities') or []
        if not entities:
            break
        for it in entities:
            attrs = it.get('attributes') or {}
            name = attrs.get('name') or attrs.get('columnName')
            qn = attrs.get('qualifiedName') or it.get('qualifiedName')
            classes = it.get('classifications') or []
            class_names = []
            for c in classes:
                if isinstance(c, dict):
                    n = c.get('typeName') or c.get('name')
                    if n: class_names.append(n)
            if classification_filter:
                lset = {x.lower() for x in class_names}
                if not any(cf.lower() in lset for cf in classification_filter):
                    continue
            cols.append({'column_name': name, 'qualifiedName': qn, 'classification_names': sorted(set(class_names))})
        if len(entities) < 200:
            break
        offset += 200
        page += 1
    return cols
